firmware_template.source:
#include "motor_brushless.h"
#include <SimpleFOC.h>
static BLDCMotor motor(7);
static BLDCDriver3PWM driver(25,26,27);
void gimbal_setup(){driver.voltage_power_supply=12;driver.init();motor.linkDriver(&driver);motor.controller=MotionControlType::angle;motor.init();Serial.println("[gimbal] OK");}
void gimbal_loop(){motor.loopFOC();motor.move();}
void gimbal_set_angle(float a){motor.target=a;}
float gimbal_get_angle(){return motor.shaft_angle;}
